import React from "react";
import axios from "axios";

const API = "http://localhost:5064/api"; // Endpoint spécifique aux formations

interface DeleteFormationButtonProps {
    id: number;                  // L'identifiant de la formation à supprimer
    onDeleteSuccess: () => void; // Fonction à appeler après une suppression réussie
}

export default function DeleteFormationButton({ id, onDeleteSuccess }: DeleteFormationButtonProps) {
    const handleClick = async () => {
        if (window.confirm("Voulez-vous vraiment supprimer cette formation ?")) {
            try {
                await axios.delete(`${API}/formation/${id}`);
                onDeleteSuccess();  // Rafraîchit la liste après suppression
            } catch (error) {
                console.log("Erreur lors de la suppression :", error);
            }
        }
    };

    return (
        <button className="DeleteButton" onClick={handleClick}>
            Supprimer
        </button>
    );
}
